  ('fire-eq-tech-moex-03230', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依滅火器用滅火藥劑認可基準規定，乾粉之主成分為碳酸氫鉀（KHCO）85％以上者，稱之為何種乾粉滅 3 火劑？', '["多效磷鹽乾粉，ABC乾粉", "普通乾粉，BC乾粉", "紫焰乾粉，KBC乾粉", "氯化鉀乾粉，XBC-CL乾粉"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "56345476ce35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 4, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03231', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '應選擇設置水霧、泡沫、乾粉、二氧化碳滅火設備等，其外牆開口面積（常時開放部分）達該層樓地板面 積百分之多少以上者，依各類場所消防安全設備設置標準各該滅火設備得採移動式設置？', '["百分之十以上", "百分之十五以上", "百分之二十以上", "百分之二十五以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "56345476ce35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 5, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03232', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '應設置無線電通信輔助設備，依各類場所消防安全設備設置標準是指樓高在幾公尺以上建築物之地下層或 總樓地板面積在幾平方公尺以上之地下建築物？', '["30公尺；500平方公尺", "50公尺；600平方公尺", "60公尺；700平方公尺", "100公尺；1000平方公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "56345476ce35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 6, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03233', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '防火水幕之防護高度在十公尺以下時，依防火牆及防火水幕設置基準規定，其每公尺水幕長度放水量應在 每分鐘幾公升以上？', '["35公升以上", "70公升以上", "100公升以上", "130公升以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "56345476ce35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 7, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
  ('fire-eq-tech-moex-03234', 'fire-eq-tech', 'fire-eq-tech-moex-097-b8d45639', 'sub-fire-eq-tech-03', NULL, 'single_choice', '依各類場所消防安全設備設置標準所稱增建或改建部分，自何時起其樓地板面積合計逾一千平方公尺或占 原建築物總樓地板面積二分之一以上時，該建築物之消防安全設備應適用增建或改建後之標準？', '["84年7月1日", "85年7月1日", "86年7月1日", "87年7月1日"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:27+00:00", "source_pdf_sha1": "56345476ce35", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "902", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規概要", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 8, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-technician", "db_exam_id": "fire-eq-tech"}'::jsonb, NULL),
